import{_ as a,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"高度な機能","description":"Clawdbot の高度な機能設定を学びます。AI モデル設定、マルチエージェント連携、ブラウザ自動化、コマンド実行ツール、Web 検索ツール、Canvas 可視化インターフェース、音声ウェイクアップと TTS、メモリシステム、Cron 定期タスク、スキルプラットフォーム、セキュリティサンドボックス、リモート Gateway を含みます。","frontmatter":{"title":"高度な機能","sidebarTitle":"AI の超能力をアンロック","subtitle":"高度な機能","description":"Clawdbot の高度な機能設定を学びます。AI モデル設定、マルチエージェント連携、ブラウザ自動化、コマンド実行ツール、Web 検索ツール、Canvas 可視化インターフェース、音声ウェイクアップと TTS、メモリシステム、Cron 定期タスク、スキルプラットフォーム、セキュリティサンドボックス、リモート Gateway を含みます。","prerequisite":["/ja/moltbot/moltbot/start/getting-started","/ja/moltbot/moltbot/start/gateway-startup"],"order":185},"headers":[],"relativePath":"ja/moltbot/moltbot/advanced/index.md","filePath":"ja/moltbot/moltbot/advanced/index.md"}'),d={name:"ja/moltbot/moltbot/advanced/index.md"};function l(h,t,i,n,s,b){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><h2 id="本章の概要" tabindex="-1">本章の概要 <a class="header-anchor" href="#本章の概要" aria-label="Permalink to &quot;本章の概要&quot;">​</a></h2><p>本章では Clawdbot の高度な機能を詳しく紹介し、AI アシスタントの強力な機能を最大限に活用できるようにします。AI モデル設定とマルチエージェント連携から、ブラウザ自動化、メモリシステム、音声機能まで、ニーズに合わせて学習内容を選択できます。</p><div class="info custom-block"><p class="custom-block-title">前提条件</p><p>本章を学習する前に、以下の内容を完了してください：</p><ul><li><a href="./../../start/getting-started/">クイックスタート</a></li><li><a href="./../../start/gateway-startup/">Gateway の起動</a></li></ul></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>ニーズに合わせて、異なる学習パスを選択できます：</p><h3 id="🚀-クイックスタートパス-初心者向け" tabindex="-1">🚀 クイックスタートパス（初心者向け） <a class="header-anchor" href="#🚀-クイックスタートパス-初心者向け" aria-label="Permalink to &quot;🚀 クイックスタートパス（初心者向け）&quot;">​</a></h3><ol><li><a href="./models-auth/">AI モデルと認証設定</a> - お好みの AI モデルを設定する</li><li><a href="./tools-exec/">コマンド実行ツールと承認</a> - AI がコマンドを安全に実行できるようにする</li><li><a href="./tools-web/">Web 検索とスクレイピングツール</a> - AI の知識取得能力を拡張する</li></ol><h3 id="🤖-ai-能力拡張パス" tabindex="-1">🤖 AI 能力拡張パス <a class="header-anchor" href="#🤖-ai-能力拡張パス" aria-label="Permalink to &quot;🤖 AI 能力拡張パス&quot;">​</a></h3><ol><li><a href="./session-management/">セッション管理とマルチエージェント</a> - AI 連携メカニズムを理解する</li><li><a href="./memory-system/">メモリシステムとベクトル検索</a> - AI に重要な情報を覚えさせる</li><li><a href="./skills-platform/">スキルプラットフォームと ClawdHub</a> - スキルパッケージの使用と共有</li></ol><h3 id="🔧-自動化ツールパス" tabindex="-1">🔧 自動化ツールパス <a class="header-anchor" href="#🔧-自動化ツールパス" aria-label="Permalink to &quot;🔧 自動化ツールパス&quot;">​</a></h3><ol><li><a href="./tools-browser/">ブラウザ自動化ツール</a> - Web 操作の自動化</li><li><a href="./cron-automation/">Cron 定期タスクと Webhook</a> - 定期タスクとイベントトリガー</li><li><a href="./remote-gateway/">リモート Gateway と Tailscale</a> - AI アシスタントへのリモートアクセス</li></ol><h3 id="🎨-インタラクション体験パス" tabindex="-1">🎨 インタラクション体験パス <a class="header-anchor" href="#🎨-インタラクション体験パス" aria-label="Permalink to &quot;🎨 インタラクション体験パス&quot;">​</a></h3><ol><li><a href="./canvas/">Canvas 可視化インターフェースと A2UI</a> - 可視化インタラクションインターフェース</li><li><a href="./voice-tts/">音声ウェイクアップとテキスト読み上げ</a> - 音声インタラクション機能</li></ol><h3 id="🔒-セキュリティとデプロイパス" tabindex="-1">🔒 セキュリティとデプロイパス <a class="header-anchor" href="#🔒-セキュリティとデプロイパス" aria-label="Permalink to &quot;🔒 セキュリティとデプロイパス&quot;">​</a></h3><ol><li><a href="./security-sandbox/">セキュリティとサンドボックス分離</a> - セキュリティメカニズムを深く理解する</li><li><a href="./remote-gateway/">リモート Gateway と Tailscale</a> - 安全なリモートアクセス</li></ol><h2 id="サブページナビゲーション" tabindex="-1">サブページナビゲーション <a class="header-anchor" href="#サブページナビゲーション" aria-label="Permalink to &quot;サブページナビゲーション&quot;">​</a></h2><h3 id="コア設定" tabindex="-1">コア設定 <a class="header-anchor" href="#コア設定" aria-label="Permalink to &quot;コア設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./models-auth/">AI モデルと認証設定</a></td><td>Anthropic、OpenAI、OpenRouter、Ollama など複数の AI モデルプロバイダと認証方式を設定する</td><td>15 分</td></tr><tr><td><a href="./session-management/">セッション管理とマルチエージェント</a></td><td>セッションモデル、セッション分離、サブエージェント連携、コンテキスト圧縮などのコア概念を学ぶ</td><td>20 分</td></tr></tbody></table><h3 id="ツールシステム" tabindex="-1">ツールシステム <a class="header-anchor" href="#ツールシステム" aria-label="Permalink to &quot;ツールシステム&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./tools-browser/">ブラウザ自動化ツール</a></td><td>ブラウザツールを使用して Web 自動化、スクリーンショット、フォーム操作などを行う</td><td>25 分</td></tr><tr><td><a href="./tools-exec/">コマンド実行ツールと承認</a></td><td>exec ツールを設定・使用し、セキュリティ承認メカニズムと権限制御を理解する</td><td>15 分</td></tr><tr><td><a href="./tools-web/">Web 検索とスクレイピングツール</a></td><td>web_search および web_fetch ツールを使用して Web 検索とコンテンツスクレイピングを行う</td><td>20 分</td></tr></tbody></table><h3 id="インタラクション体験" tabindex="-1">インタラクション体験 <a class="header-anchor" href="#インタラクション体験" aria-label="Permalink to &quot;インタラクション体験&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./canvas/">Canvas 可視化インターフェースと A2UI</a></td><td>Canvas A2UI プッシュメカニズム、可視化インターフェース操作、カスタムインターフェースを理解する</td><td>20 分</td></tr><tr><td><a href="./voice-tts/">音声ウェイクアップとテキスト読み上げ</a></td><td>Voice Wake、Talk Mode、TTS プロバイダを設定し、音声インタラクションを実現する</td><td>15 分</td></tr></tbody></table><h3 id="インテリジェンス拡張" tabindex="-1">インテリジェンス拡張 <a class="header-anchor" href="#インテリジェンス拡張" aria-label="Permalink to &quot;インテリジェンス拡張&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./memory-system/">メモリシステムとベクトル検索</a></td><td>メモリシステム（SQLite-vec、FTS5、ハイブリッド検索）を設定・使用する</td><td>25 分</td></tr><tr><td><a href="./skills-platform/">スキルプラットフォームと ClawdHub</a></td><td>スキルシステム、Bundled/Managed/Workspace スキル、ClawdHub 統合を理解する</td><td>20 分</td></tr></tbody></table><h3 id="自動化とデプロイ" tabindex="-1">自動化とデプロイ <a class="header-anchor" href="#自動化とデプロイ" aria-label="Permalink to &quot;自動化とデプロイ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./cron-automation/">Cron 定期タスクと Webhook</a></td><td>定期タスク、Webhook トリガー、Gmail Pub/Sub などの自動化機能を設定する</td><td>20 分</td></tr><tr><td><a href="./remote-gateway/">リモート Gateway と Tailscale</a></td><td>Tailscale Serve/Funnel または SSH トンネル経由で Gateway にリモートアクセスする</td><td>15 分</td></tr></tbody></table><h3 id="セキュリティメカニズム" tabindex="-1">セキュリティメカニズム <a class="header-anchor" href="#セキュリティメカニズム" aria-label="Permalink to &quot;セキュリティメカニズム&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トピック</th><th>説明</th><th>所要時間</th></tr></thead><tbody><tr><td><a href="./security-sandbox/">セキュリティとサンドボックス分離</a></td><td>セキュリティモデル、ツール権限制御、サンドボックス分離、Docker 化デプロイを理解する</td><td>20 分</td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章の学習を完了した後、次のことができます：</p><ol><li><strong>深く学習</strong> - <a href="./../../faq/troubleshooting/">トラブルシューティング</a> を参照して遭遇した問題を解決する</li><li><strong>デプロイを理解</strong> - <a href="./../../appendix/deployment/">デプロイオプション</a> を参照して Clawdbot を本番環境にデプロイする</li><li><strong>拡張機能を開発</strong> - <a href="./../../appendix/development/">開発ガイド</a> を参照してプラグインの開発方法とコードへの貢献方法を学ぶ</li><li><strong>設定を確認</strong> - <a href="./../../appendix/config-reference/">完全設定リファレンス</a> を参照してすべての設定オプションを理解する</li></ol><div class="tip custom-block"><p class="custom-block-title">学習アドバイス</p><p>実際のニーズに合わせて学習パスを選択することをお勧めします。どこから始めればよいか分からない場合は、「クイックスタートパス」に沿って段階的に学習できます。他のトピックは必要に応じて深く学習できます。</p></div>',33)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
